def.body:
@mutex.synchronize do
  channel = read.channel
  if @data.has_key?(channel)
    existing = @data[channel]
    if existing.id == read.id
      @replaced_chunks = @replaced_chunks + 1
    else
      @missed_reads = @missed_reads + 1
    end
    @order.delete(channel)
  elsif @data.size >= @capacity
    evicted_channel = @order.shift
    @data.delete(evicted_channel)
    @missed_reads = @missed_reads + 1
  end

  @data[channel] = read
  @order << channel
end

@running.set(0)
if bidi = @bidi
  begin
    bidi.close_send
  rescue
    nil
  end
  begin
    bidi.cancel
  rescue
    nil
  end
end
@buffer.clear
@action_mutex.synchronize do
  @action_queue.clear
  @sent_actions.clear
end
@seen_read_ids.clear
